package com.google.gson;
import com.google.gson.internal.Streams;
import com.google.gson.stream.JsonWriter;
import java.io.IOException;
import java.io.StringWriter;
import java.math.BigDecimal;
import java.math.BigInteger;
import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.JsonElement;
import com.google.gson.JsonObject;
import org.junit.jupiter.api.Test;

class JsonElementTest {

  @Test
  void getAsJsonObject_whenIsJsonObjectTrue_returnsThisAsJsonObject() {
    JsonElement jsonElement = mock(JsonElement.class, withSettings().defaultAnswer(CALLS_REAL_METHODS));
    when(jsonElement.isJsonObject()).thenReturn(true);
    // Cast to JsonObject must be safe since isJsonObject() returns true
    // So mock JsonElement also as JsonObject
    JsonObject jsonObjectMock = mock(JsonObject.class);
    // We need to make the mock return itself casted to JsonObject
    // So let's use a spy on JsonObject to simulate this behavior
    JsonElement spyElement = spy(jsonObjectMock);
    doReturn(true).when(spyElement).isJsonObject();

    JsonObject result = spyElement.getAsJsonObject();
    assertSame(spyElement, result);
  }

  @Test
  void getAsJsonObject_whenIsJsonObjectFalse_throwsIllegalStateException() {
    JsonElement jsonElement = mock(JsonElement.class, withSettings().defaultAnswer(CALLS_REAL_METHODS));
    when(jsonElement.isJsonObject()).thenReturn(false);
    when(jsonElement.toString()).thenReturn("mockedJsonElement");
    IllegalStateException exception = assertThrows(IllegalStateException.class, jsonElement::getAsJsonObject);
    assertEquals("Not a JSON Object: mockedJsonElement", exception.getMessage());
  }
}
